// Extract and enrich lead data
const leadData = $input.item.json;

// Get profile information
const firstName = leadData.firstName || leadData.author?.firstName || 'Unknown';
const lastName = leadData.lastName || leadData.author?.lastName || '';
const headline = leadData.headline || leadData.author?.headline || 'Not provided';
const profileUrl = leadData.profileUrl || leadData.vanityName ? `https://linkedin.com/in/${leadData.vanityName}` : 'N/A';
const company = leadData.company || extractCompanyFromHeadline(headline);
const location = leadData.location || 'Unknown';

// Determine lead source
let leadSource = 'Unknown';
let engagementType = 'None';
let engagementScore = 0;

if (leadData.connectionStatus) {
  leadSource = 'New Connection';
  engagementScore = 50;
} 

if (leadData.text || leadData.commentText) {
  leadSource = leadData.connectionStatus ? 'Connection + Engagement' : 'Post Engagement';
  engagementType = 'Comment';
  engagementScore += 30;
}

if (leadData.reaction || leadData.liked) {
  if (leadSource === 'Unknown') leadSource = 'Post Engagement';
  engagementType = engagementType === 'Comment' ? 'Comment + Like' : 'Like';
  engagementScore += 10;
}

// Calculate lead quality score (0-100)
let qualityScore = engagementScore;

// Bonus points for complete profile
if (headline !== 'Not provided') qualityScore += 10;
if (company !== 'Unknown') qualityScore += 10;
if (location !== 'Unknown') qualityScore += 5;

// Determine lead temperature
let leadTemperature = 'Cold';
if (qualityScore >= 70) leadTemperature = 'Hot';
else if (qualityScore >= 50) leadTemperature = 'Warm';

// Extract company from headline helper function
function extractCompanyFromHeadline(headline) {
  const patterns = [
    /at ([^|•]+)/i,
    /@ ([^|•]+)/i,
    /\| ([^|•]+)/i
  ];

  for (const pattern of patterns) {
    const match = headline.match(pattern);
    if (match) return match[1].trim();
  }

  return 'Unknown';
}

// Create timestamp
const timestamp = new Date().toISOString();
const dateAdded = new Date().toLocaleDateString('en-US');

// Build enriched lead object
return {
  json: {
    // Basic Info
    leadId: leadData.id || `lead_${Date.now()}`,
    firstName,
    lastName,
    fullName: `${firstName} ${lastName}`.trim(),
    email: leadData.email || '',
    phone: leadData.phone || '',

    // Professional Info
    headline,
    company,
    position: headline.split('at')[0]?.trim() || headline.split('|')[0]?.trim() || 'Not specified',
    location,
    profileUrl,

    // Lead Intelligence
    leadSource,
    leadTemperature,
    qualityScore,
    engagementType,
    engagementScore,

    // Engagement Details
    commentText: leadData.text || leadData.commentText || '',
    reactionType: leadData.reaction || '',
    postUrl: leadData.postUrl || '',

    // Metadata
    dateAdded,
    timestamp,
    lastUpdated: timestamp,
    status: 'New',
    assignedTo: '',
    notes: '',

    // Original data for reference
    originalData: leadData
  }
};

// Check if lead already exists in our system
const leadId = $input.item.json.leadId;
const profileUrl = $input.item.json.profileUrl;

// Use workflow static data to track processed leads
const processedLeads = $getWorkflowStaticData('global').processedLeads || {};

// Create unique identifier (prefer profileUrl, fallback to leadId)
const uniqueId = profileUrl !== 'N/A' ? profileUrl : leadId;

if (processedLeads[uniqueId]) {
  // Lead exists - update engagement data only
  const existing = processedLeads[uniqueId];

  return {
    json: {
      ...$input.item.json,
      isDuplicate: true,
      isUpdate: true,
      existingData: existing,
      action: 'update'
    }
  };
}

// New lead - add to tracking
processedLeads[uniqueId] = {
  timestamp: new Date().toISOString(),
  leadId,
  profileUrl,
  firstName: $input.item.json.firstName,
  lastName: $input.item.json.lastName,
  company: $input.item.json.company
};

// Clean up old entries (older than 90 days)
const ninetyDaysAgo = Date.now() - (90 * 24 * 60 * 60 * 1000);
for (const key in processedLeads) {
  const entryTime = new Date(processedLeads[key].timestamp).getTime();
  if (entryTime < ninetyDaysAgo) {
    delete processedLeads[key];
  }
}

// Save back to static data
$getWorkflowStaticData('global').processedLeads = processedLeads;

return {
  json: {
    ...$input.item.json,
    isDuplicate: false,
    isUpdate: false,
    action: 'create'
  }
};

// Generate notification message
const lead = $input.item.json;

let message = `🎉 NEW LINKEDIN LEAD CAPTURED!\n\n`;
message += `👤 Name: ${lead.fullName}\n`;
message += `🏢 Company: ${lead.company}\n`;
message += `💼 Position: ${lead.position}\n`;
message += `🌡️ Temperature: ${lead.leadTemperature}\n`;
message += `⭐ Quality Score: ${lead.qualityScore}/100\n`;
message += `📍 Source: ${lead.leadSource}\n`;

if (lead.engagementType !== 'None') {
  message += `💬 Engagement: ${lead.engagementType}\n`;
}

if (lead.commentText) {
  message += `\n💭 Comment: "${lead.commentText.substring(0, 100)}${lead.commentText.length > 100 ? '...' : ''}"\n`;
}

message += `\n🔗 Profile: ${lead.profileUrl}\n`;
message += `\n✅ Added to: Google Sheets${lead.action === 'create' ? ' + CRM' : ' (Updated)'}\n`;
message += `⏰ Captured: ${lead.dateAdded}`;

return {
  json: {
    ...lead,
    notificationMessage: message,
    notificationTitle: `${lead.leadTemperature} Lead: ${lead.fullName}`,
    shouldNotify: lead.leadTemperature === 'Hot' || lead.leadTemperature === 'Warm'
  }
};

// Log successful processing
const timestamp = new Date().toISOString();
const lead = $input.item.json;

console.log(`✅ SUCCESS: ${lead.action === 'create' ? 'Created' : 'Updated'} lead: ${lead.fullName} | Company: ${lead.company} | Score: ${lead.qualityScore} | Temperature: ${lead.leadTemperature} | Source: ${lead.leadSource} | Time: ${timestamp}`);

// Track statistics
const stats = $getWorkflowStaticData('global').stats || {
  totalLeads: 0,
  hotLeads: 0,
  warmLeads: 0,
  coldLeads: 0,
  lastProcessed: null
};

if (lead.action === 'create') {
  stats.totalLeads++;
  if (lead.leadTemperature === 'Hot') stats.hotLeads++;
  else if (lead.leadTemperature === 'Warm') stats.warmLeads++;
  else stats.coldLeads++;
}

stats.lastProcessed = timestamp;
$getWorkflowStaticData('global').stats = stats;

return {
  json: {
    success: true,
    action: lead.action,
    leadId: lead.leadId,
    leadName: lead.fullName,
    leadTemperature: lead.leadTemperature,
    qualityScore: lead.qualityScore,
    timestamp,
    cumulativeStats: stats
  }
};
